// Persistent AI chat sessions backed by Durable Object SQLite. One DO per
// docs site (keyed by projectId when authenticated, docs host otherwise);
// each conversation is a row keyed by an unguessable session id (chs_...,
// 256-bit CSPRNG bearer token generated by the vite proxy).
//
// Storage model: snapshot-on-completion. After each chat turn the gateway
// replaces the session's full ModelMessage[] history. Snapshots are
// race-free enough because the DO serializes writes and the client already
// round-trips the full history on every request (last write wins).
//
// Cleanup: a daily alarm prunes sessions idle for more than SESSION_TTL_MS.
// A per-site session cap evicts the oldest sessions so unauthenticated
// visitors cannot grow storage unboundedly.

import { DurableObject } from 'cloudflare:workers'

/** Sessions idle longer than this are pruned by the daily alarm. */
export const SESSION_TTL_MS = 30 * 24 * 60 * 60 * 1000
/** Max conversations kept per site; oldest (by updated_at) are evicted. */
export const MAX_SESSIONS_PER_SITE = 500
/** Hard cap on a single snapshot payload. The gateway trims oldest messages
 *  before saving; this is the DO-side backstop against abusive payloads. */
export const MAX_SNAPSHOT_BYTES = 2 * 1024 * 1024

const ALARM_INTERVAL_MS = 24 * 60 * 60 * 1000

export class ChatSessionDO extends DurableObject<Env> {
  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env)
    this.ctx.storage.sql.exec(`
      CREATE TABLE IF NOT EXISTS chat_session (
        session_id TEXT PRIMARY KEY,
        page_slug TEXT NOT NULL DEFAULT '',
        model_messages_json TEXT NOT NULL,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL
      )
    `)
    this.ctx.storage.sql.exec(`
      CREATE INDEX IF NOT EXISTS idx_chat_session_updated
      ON chat_session (updated_at)
    `)
  }

  /** Upsert the full ModelMessage[] snapshot for one conversation.
   *  Messages travel as a JSON string — workerd RPC type mapping rejects
   *  `unknown[]` (non-Serializable), and strings avoid double parsing. */
  async saveSnapshot(args: {
    sessionId: string
    pageSlug: string
    modelMessagesJson: string
  }): Promise<{ saved: boolean }> {
    const json = args.modelMessagesJson
    // Real UTF-8 bytes, not UTF-16 code units (string.length undercounts).
    if (new TextEncoder().encode(json).byteLength > MAX_SNAPSHOT_BYTES) {
      return { saved: false }
    }
    const now = Date.now()
    this.ctx.storage.sql.exec(
      `INSERT INTO chat_session (session_id, page_slug, model_messages_json, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?)
       ON CONFLICT (session_id) DO UPDATE SET
         page_slug = excluded.page_slug,
         model_messages_json = excluded.model_messages_json,
         updated_at = excluded.updated_at`,
      args.sessionId,
      args.pageSlug,
      json,
      now,
      now,
    )

    // Evict oldest sessions above the per-site cap so storage stays bounded.
    this.ctx.storage.sql.exec(
      `DELETE FROM chat_session WHERE session_id IN (
         SELECT session_id FROM chat_session
         ORDER BY updated_at DESC
         LIMIT -1 OFFSET ?
       )`,
      MAX_SESSIONS_PER_SITE,
    )

    // Ensure the daily prune alarm is scheduled while data exists.
    const alarm = await this.ctx.storage.getAlarm()
    if (alarm === null) {
      await this.ctx.storage.setAlarm(now + ALARM_INTERVAL_MS)
    }
    return { saved: true }
  }

  /** Load one conversation's snapshot JSON, or null when unknown/expired. */
  async getSnapshot(args: { sessionId: string }): Promise<{ modelMessagesJson: string } | null> {
    const rows = this.ctx.storage.sql
      .exec(
        `SELECT model_messages_json, updated_at FROM chat_session WHERE session_id = ?`,
        args.sessionId,
      )
      .toArray()
    const row = rows[0]
    if (!row) return null
    if ((row.updated_at as number) < Date.now() - SESSION_TTL_MS) {
      this.ctx.storage.sql.exec(`DELETE FROM chat_session WHERE session_id = ?`, args.sessionId)
      return null
    }
    return { modelMessagesJson: row.model_messages_json as string }
  }

  /** Delete one conversation (user pressed "New chat"). */
  async clearSession(args: { sessionId: string }): Promise<void> {
    this.ctx.storage.sql.exec(`DELETE FROM chat_session WHERE session_id = ?`, args.sessionId)
  }

  /** Daily prune of idle sessions. Reschedules while any rows remain so an
   *  abandoned site's DO eventually empties out and stops alarming. */
  async alarm(): Promise<void> {
    this.ctx.storage.sql.exec(
      `DELETE FROM chat_session WHERE updated_at < ?`,
      Date.now() - SESSION_TTL_MS,
    )
    const remaining = this.ctx.storage.sql
      .exec(`SELECT COUNT(*) AS n FROM chat_session`)
      .one()
    if ((remaining.n as number) > 0) {
      await this.ctx.storage.setAlarm(Date.now() + ALARM_INTERVAL_MS)
    }
  }
}
